import os
from kafka.admin import AdminTool
from kafka import KafkaAdminClient

def create_topic(admin_client, topic_name, num_partitions=1, replication_factor=3):
    try:
        admin_client.create_topics(new_topics=[{"topic": topic_name, "num_partitions": num_partitions, "replication_factor": replication_factor}], validate_only=False)
    except Exception as e:
        print(f"Failed to create topic {topic_name}: {str(e)}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
    except Exception as e:
        print(f"Failed to delete topic {topic_name}: {str(e)}")

def list_partitions(admin_client, topic_name):
    partitions = admin_client.list_topics(topic_name=topic_name).partitions
    for partition in partitions:
        print(partition)

def set_config(admin_client, topic_name, config=None):
    try:
        admin_client.alter_replica_assignment(topics=[{"topic": topic_name, "new_replicas": [config["replication_factor"]]}])
    except Exception as e:
        print(f"Failed to configure topic {topic_name}: {str(e)}")

def main():
    # Read command-line arguments
    import argparse
    parser = argparse.ArgumentParser()
    parser.add_argument("-a", "--action", type=str, required=True)
    parser.add_argument("-t", "--topics", nargs="*", default=["*"])
    args = parser.parse_args()

    # Create admin client
    bootstrap_servers = [os.environ.get("KAFKA_BOOTSTRAP_SERVERS")]
    admin_client = KafkaAdminClient(bootstrap_servers=bootstrap_servers, client_id='kafka_admin')

    if args.action == "create":
        for topic in args.topics:
            create_topic(admin_client, topic)
    elif args.action == "delete":
        for topic in args.topics:
            delete_topic(admin_client, topic)
    elif args.action == "list_partitions":
        for topic in args.topics:
            list_partitions(admin_client, topic)
    elif args.action == "set_config":
        config = {}
        if args.topics[0] != "*":
            config["replication_factor"] = int(args.topics[0])
        set_config(admin_client, args.topics[1], config)

if __name__ == "__main__":
    main()